knowledge.js:
const products = [
  { id: 1, name: 'Wireless Headphones', price: 79.99, image: 'https://via.placeholder.com/300x200?text=Headphones', category: 'Electronics' },
  { id: 2, name: 'Running Shoes', price: 59.99, image: 'https://via.placeholder.com/300x200?text=Shoes', category: 'Fashion' },
  { id: 3, name: 'Coffee Mug', price: 14.99, image: 'https://via.placeholder.com/300x200?text=Mug', category: 'Kitchen' },
  { id: 4, name: 'Laptop Stand', price: 39.99, image: 'https://via.placeholder.com/300x200?text=Stand', category: 'Electronics' }
];
let cart = [];
function renderProducts() {
  const grid = document.getElementById('products-grid');
  grid.innerHTML = products.map(p => `<div class='product-card'><img src='${p.image}' alt='${p.name}'><div class='product-info'><h3>${p.name}</h3><p>${p.category}</p><p class='price'>$${p.price}</p><button class='add-btn' onclick='addToCart(${p.id})'>Add to Cart</button></div></div>`).join('');
}
function addToCart(id) {
  const product = products.find(p => p.id === id);
  const existing = cart.find(c => c.id === id);
  if (existing) existing.qty++;
  else cart.push({...product, qty: 1});
  updateCart();
}
function updateCart() {
  document.getElementById('cart-count').textContent = cart.reduce((s, c) => s + c.qty, 0);
  document.getElementById('cart-items').innerHTML = cart.map(c => `<div style='padding:0.5rem 0;border-bottom:1px solid #eee'>${c.name} x${c.qty} - $${(c.price*c.qty).toFixed(2)}</div>`).join('');
  document.getElementById('total').textContent = cart.reduce((s, c) => s + c.price*c.qty, 0).toFixed(2);
  document.getElementById('cart-sidebar').classList.add('open');
}
function checkout() { alert('Order placed! Thank you for shopping!'); cart = []; updateCart(); document.getElementById('cart-sidebar').classList.remove('open'); }
document.querySelector('.cart-icon').onclick = () => document.getElementById('cart-sidebar').classList.toggle('open');
renderProducts();

