let tasks = JSON.parse(localStorage.getItem('tasks') || '[]');
function render() {
  const list = document.getElementById('task-list');
  list.innerHTML = tasks.map((t, i) => `<li class='${t.done ? 'done' : ''}'><input type='checkbox' ${t.done ? 'checked' : ''} onchange='toggle(${i})'><span>${t.text}</span><button class='delete-btn' onclick='remove(${i})'>🗑️</button></li>`).join('');
  const done = tasks.filter(t => t.done).length;
  document.getElementById('stats-text').textContent = `${done} of ${tasks.length} tasks completed`;
  localStorage.setItem('tasks', JSON.stringify(tasks));
}
function addTask() {
  const input = document.getElementById('task-input');
  if (!input.value.trim()) return;
  tasks.push({ text: input.value.trim(), done: false });
  input.value = '';
  render();
}
function toggle(i) { tasks[i].done = !tasks[i].done; render(); }
function remove(i) { tasks.splice(i, 1); render(); }
document.getElementById('task-input').addEventListener('keypress', e => { if (e.key === 'Enter') addTask(); });
render();

